import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { studentAPI } from '../services/api';

const FEE_BADGE = {
  paid:    { bg: '#D1FAE5', c: '#065F46', l: '✓ Paid' },
  pending: { bg: '#FEE2E2', c: '#991B1B', l: 'Pending' },
  partial: { bg: '#FEF3C7', c: '#92400E', l: 'Partial' },
};

export default function Students() {
  const [params, setParams] = useState({ page: 1, limit: 15, search: '' });
  const { data, isLoading } = useQuery({
    queryKey: ['students', params],
    queryFn: () => studentAPI.getAll(params).then(r => r.data)
  });

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 18 }}>
        <div>
          <h2 style={{ fontSize: 20, fontWeight: 700 }}>Students</h2>
          <p style={{ fontSize: 12, color: '#6B7280', marginTop: 2 }}>{data?.pagination?.total || 0} students enrolled</p>
        </div>
        <button style={{ padding: '8px 16px', background: '#2D1B69', color: '#fff', border: 'none', borderRadius: 8, fontSize: 12, fontWeight: 600, cursor: 'pointer' }}>
          + New Admission
        </button>
      </div>

      <div style={{ display: 'flex', gap: 10, marginBottom: 14 }}>
        <input placeholder="🔍 Search by name or admission number…" value={params.search}
          onChange={e => setParams({ ...params, search: e.target.value, page: 1 })}
          style={{ flex: 1, maxWidth: 320, padding: '8px 12px', border: '1px solid #E5E7EB', borderRadius: 8, fontSize: 12, outline: 'none' }} />
        <select style={{ padding: '8px 12px', border: '1px solid #E5E7EB', borderRadius: 8, fontSize: 12, outline: 'none', background: '#fff' }}>
          <option>All Classes</option>
          {['6','7','8','9','10','11','12'].map(c => <option key={c}>Class {c}</option>)}
        </select>
        <select style={{ padding: '8px 12px', border: '1px solid #E5E7EB', borderRadius: 8, fontSize: 12, outline: 'none', background: '#fff' }}>
          <option>Fee: All</option>
          <option>Paid</option>
          <option>Pending</option>
          <option>Partial</option>
        </select>
      </div>

      <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 14, overflow: 'hidden' }}>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
            <thead>
              <tr style={{ background: '#F9FAFB' }}>
                {['Adm. No.', 'Student', 'Class', 'Parent / Mobile', 'Category', 'Fee Status', 'Status', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '9px 12px', textAlign: 'left', color: '#6B7280', fontSize: 10, fontWeight: 600, textTransform: 'uppercase', whiteSpace: 'nowrap', borderBottom: '0.5px solid #E5E7EB' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {isLoading && (
                <tr><td colSpan={8} style={{ textAlign: 'center', padding: 40, color: '#9CA3AF' }}>Loading students…</td></tr>
              )}
              {!isLoading && !data?.data?.length && (
                <tr><td colSpan={8} style={{ textAlign: 'center', padding: 40, color: '#9CA3AF' }}>No students found</td></tr>
              )}
              {(data?.data || []).map(s => {
                const fb = FEE_BADGE[s.fee_status] || FEE_BADGE.pending;
                return (
                  <tr key={s.id} style={{ borderBottom: '0.5px solid #F3F4F6', transition: 'background .1s' }}
                    onMouseEnter={e => e.currentTarget.style.background = '#EDE9F8'}
                    onMouseLeave={e => e.currentTarget.style.background = ''}>
                    <td style={{ padding: '10px 12px', fontFamily: 'monospace', fontSize: 11, color: '#9CA3AF' }}>{s.admission_no}</td>
                    <td style={{ padding: '10px 12px' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                        <div style={{ width: 28, height: 28, borderRadius: 7, background: '#EDE9F8', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, fontWeight: 700, color: '#2D1B69', flexShrink: 0 }}>
                          {s.first_name?.[0]}
                        </div>
                        <span style={{ fontWeight: 600 }}>{s.first_name} {s.last_name}</span>
                      </div>
                    </td>
                    <td style={{ padding: '10px 12px', color: '#6B7280' }}>{s.class_name} {s.section_name}</td>
                    <td style={{ padding: '10px 12px' }}>
                      <div style={{ fontWeight: 500 }}>{s.parent_name}</div>
                      <div style={{ fontSize: 10, color: '#9CA3AF' }}>{s.parent_phone}</div>
                    </td>
                    <td style={{ padding: '10px 12px' }}>
                      <span style={{ padding: '2px 8px', borderRadius: 20, fontSize: 10, background: '#F3F4F6', color: '#374151' }}>{s.category}</span>
                    </td>
                    <td style={{ padding: '10px 12px' }}>
                      <span style={{ padding: '2px 8px', borderRadius: 20, fontSize: 10, background: fb.bg, color: fb.c }}>{fb.l}</span>
                    </td>
                    <td style={{ padding: '10px 12px' }}>
                      <span style={{ padding: '2px 8px', borderRadius: 20, fontSize: 10, background: s.status === 'active' ? '#D1FAE5' : '#F3F4F6', color: s.status === 'active' ? '#065F46' : '#374151' }}>
                        {s.status}
                      </span>
                    </td>
                    <td style={{ padding: '10px 12px' }}>
                      <div style={{ display: 'flex', gap: 5 }}>
                        <button style={{ padding: '4px 10px', border: '1px solid #E5E7EB', borderRadius: 6, background: '#fff', fontSize: 11, cursor: 'pointer' }}>View</button>
                        <button style={{ padding: '4px 10px', border: '1px solid #E5E7EB', borderRadius: 6, background: '#fff', fontSize: 11, cursor: 'pointer' }}>ID</button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 14px', borderTop: '0.5px solid #E5E7EB', fontSize: 11, color: '#6B7280' }}>
          <span>Showing {data?.data?.length || 0} of {data?.pagination?.total || 0} students</span>
          <div style={{ display: 'flex', gap: 5 }}>
            {params.page > 1 && (
              <button onClick={() => setParams({ ...params, page: params.page - 1 })}
                style={{ padding: '4px 10px', border: '1px solid #E5E7EB', borderRadius: 6, background: '#fff', fontSize: 11, cursor: 'pointer' }}>←</button>
            )}
            <span style={{ padding: '4px 10px', background: '#2D1B69', color: '#fff', borderRadius: 6, fontSize: 11 }}>{params.page}</span>
            {data?.pagination?.hasNext && (
              <button onClick={() => setParams({ ...params, page: params.page + 1 })}
                style={{ padding: '4px 10px', border: '1px solid #E5E7EB', borderRadius: 6, background: '#fff', fontSize: 11, cursor: 'pointer' }}>→</button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
